// ============================================================================
//  glossary.js — a dictionary of the terms of art in Lilly's Christian
//  Astrology. Each entry: { term, cat (category), def, see (optional link) }.
//  `see` is a path relative to the site root used to deep-link the concept.
// ============================================================================
export const GLOSSARY = [
  // — Foundations —
  { term: 'Ascendant', cat: 'Angles', def: 'The degree of the ecliptic rising on the eastern horizon; the cusp of the 1st house. Signifies the querent or native — body, life and self.', see: 'pages/book1/reference.html#houses' },
  { term: 'Midheaven (Medium Coeli, MC)', cat: 'Angles', def: 'The degree culminating on the meridian; the cusp of the 10th house. Signifies honour, career, the mother and authority.', see: 'pages/book1/reference.html#houses' },
  { term: 'Descendant', cat: 'Angles', def: 'The western point opposite the Ascendant; cusp of the 7th house — the other party, the spouse, the open enemy.' },
  { term: 'Imum Coeli (IC)', cat: 'Angles', def: 'The lowest point opposite the MC; cusp of the 4th — the father, land, home and the end of the matter.' },
  { term: 'Cusp', cat: 'Foundations', def: 'The beginning (boundary) of a house. A planet near a cusp partakes of that house.' },
  { term: 'Angular / Succedent / Cadent', cat: 'Houses', def: 'The three house strengths. Angular (1,4,7,10) = strongest, acting swiftly; succedent (2,5,8,11) = moderate; cadent (3,6,9,12) = weakest, delaying.' },

  // — The lights, sect —
  { term: 'Luminaries', cat: 'Planets', def: 'The Sun and Moon, the two "lights." The Sun rules the day, the Moon the night.', see: 'pages/book1/reference.html#planets' },
  { term: 'Sect (Diurnal / Nocturnal)', cat: 'Dignity', def: 'Whether a chart is of the day (Sun above the horizon) or night. Sect determines which triplicity ruler applies and suits diurnal planets (Saturn, Jupiter, Sun) by day, nocturnal (Mars, Venus, Moon) by night.' },
  { term: 'Fortunes & Infortunes', cat: 'Planets', def: 'Jupiter is the Greater Fortune, Venus the Lesser; Saturn the Greater Infortune, Mars the Lesser. The Sun, Moon and Mercury are neutral; Mercury is "convertible."' },

  // — Essential dignity —
  { term: 'Essential Dignity', cat: 'Dignity', def: "A planet's strength by virtue of the sign and degree it occupies: domicile (+5), exaltation (+4), triplicity (+3), term (+2), face (+1).", see: 'pages/book1/dignities.html' },
  { term: 'Domicile (House)', cat: 'Dignity', def: 'The sign(s) a planet rules and is most at home in (e.g. Mars rules Aries and Scorpio). The strongest essential dignity, +5.', see: 'pages/book1/dignities.html' },
  { term: 'Exaltation', cat: 'Dignity', def: 'A sign (and exact degree) where a planet is honoured as an exalted guest (e.g. the Sun at 19° Aries). +4.', see: 'pages/book1/dignities.html' },
  { term: 'Triplicity', cat: 'Dignity', def: 'Rulership of one of the four elements. Lilly uses two rulers — one for day, one for night — with Mars ruling Water both day and night. +3.', see: 'pages/book1/dignities.html' },
  { term: 'Term (Bound)', cat: 'Dignity', def: 'Unequal subdivisions of a sign ruled by the five non-luminary planets. Lilly uses the Ptolemaic terms. +2.', see: 'pages/book1/dignities.html' },
  { term: 'Face (Decan)', cat: 'Dignity', def: 'A 10° third of a sign, ruled in the Chaldean order beginning with Mars at 0° Aries. The weakest dignity, +1 — its chief use is to keep a planet from being wholly peregrine.', see: 'pages/book1/dignities.html' },
  { term: 'Detriment', cat: 'Dignity', def: 'The sign opposite a planet’s domicile, where it is ill at ease. −5.', see: 'pages/book1/dignities.html' },
  { term: 'Fall', cat: 'Dignity', def: 'The sign opposite a planet’s exaltation, where it is dejected. −4.', see: 'pages/book1/dignities.html' },
  { term: 'Peregrine', cat: 'Dignity', def: '"Wandering" — a planet with no essential dignity of its own anywhere in its place, like a stranger with no standing. −5.', see: 'pages/book1/dignities.html' },
  { term: 'Almuten', cat: 'Dignity', def: 'The planet with the most essential dignity at a given degree — the "victor" or lord of that degree.', see: 'pages/book1/dignities.html' },
  { term: 'Verdict (green / amber / red)', cat: 'This site', def: "The site's chart-health and election badge: a traffic-light scale for the GRAVITY of the judgement. Green = few impediments / favourable; amber = mixed, weigh the cautions; red = strongly impeded / unfavourable. Red marks SEVERITY only — it is NOT the planetary or talisman colour red (e.g. Mars's red garment), which is a separate ritual correspondence.", see: 'pages/now.html' },
  { term: 'Dispositor', cat: 'Dignity', def: 'The planet that rules (by domicile) the sign another planet occupies; it "disposes of" the guest.' },
  { term: 'Chart Health', cat: 'This site', def: "The site's summary of a figure's soundness for judgement: a significator-weighted count of the considerations and impediments (void Moon, combustion, retrograde significators, Via Combusta and the rest) rendered as a green/amber/red verdict. A crude, quick summary — not a substitute for weighing the actual significators of the matter.", see: 'pages/workbench.html' },

  // — Accidental dignity —
  { term: 'Accidental Dignity', cat: 'Dignity', def: "A planet's strength of situation: its house, motion (direct/swift), freedom from the Sun, and contacts with benefics, malefics and fixed stars.", see: 'pages/book1/dignities.html' },
  { term: 'Oriental / Occidental', cat: 'Motion', def: 'Oriental = rising before the Sun (eastern); occidental = setting after it (western). Saturn, Jupiter, Mars are fortified oriental; Mercury and Venus occidental.' },
  { term: 'Retrograde', cat: 'Motion', def: 'Apparent backward motion through the zodiac — a strong debility (−5); the planet is hesitant, undoing, contrary.' },
  { term: 'Combust', cat: 'Sun', def: 'Within 8°30′ of the Sun (same sign) — gravely weakened, "burnt up." −5.' },
  { term: 'Cazimi', cat: 'Sun', def: 'Within 17′ of the Sun’s exact body — "in the heart of the Sun," a great fortitude. +5.' },
  { term: 'Under the Sunbeams', cat: 'Sun', def: 'Within 17° of the Sun but beyond combustion — obscured and weakened. −4.' },
  { term: 'Besieged', cat: 'Motion', def: 'A planet hemmed between the bodies of Saturn and Mars (or, favourably, between Jupiter and Venus).' },

  // — Aspects —
  { term: 'Aspect', cat: 'Aspects', def: 'A significant angular relationship between two planets. Lilly uses the five Ptolemaic aspects.', see: 'pages/book1/index.html#aspects' },
  { term: 'Conjunction (☌)', cat: 'Aspects', def: '0° apart — union; good or ill according to the planets joined.' },
  { term: 'Sextile (⚹)', cat: 'Aspects', def: '60° apart — an aspect of friendship and ease.' },
  { term: 'Square (□)', cat: 'Aspects', def: '90° apart — an aspect of imperfect enmity, obstruction, effort.' },
  { term: 'Trine (△)', cat: 'Aspects', def: '120° apart — the strongest aspect of love and ease.' },
  { term: 'Opposition (☍)', cat: 'Aspects', def: '180° apart — an aspect of perfect hatred, separation, open conflict.' },
  { term: 'Orb', cat: 'Aspects', def: 'The "body of light" around a planet within which an aspect operates. Lilly assigns orbs to PLANETS, not to aspects.', see: 'pages/book1/index.html#aspects' },
  { term: 'Moiety', cat: 'Aspects', def: 'Half of a planet’s orb. Two planets are within a platic aspect when their distance from exactitude is less than the sum of their two moieties.', see: 'pages/book1/index.html#aspects' },
  { term: 'Partile / Platic', cat: 'Aspects', def: 'Partile = an aspect exact to the degree (very strong); platic = within orb but not exact.' },
  { term: 'Dexter / Sinister', cat: 'Aspects', def: 'Dexter ("right") aspects are cast against the order of the signs and are more forcible; sinister ("left") with the order.' },
  { term: 'Applying / Separating', cat: 'Horary', def: 'An aspect is applying when the faster planet moves toward exactitude (the matter is coming about) and separating when moving away (past, or denied).', see: 'pages/book2/horary.html' },

  // — Horary technique —
  { term: 'Horary Astrology', cat: 'Horary', def: 'Answering a specific question from a chart cast for the moment it is understood — the subject of Lilly’s Book II.', see: 'pages/book2/index.html' },
  { term: 'Querent', cat: 'Horary', def: 'The person who asks the question — signified by the 1st house, its ruler, and the Moon.', see: 'pages/book2/index.html' },
  { term: 'Quesited', cat: 'Horary', def: 'The person or matter asked about — signified by the relevant house and its ruler.', see: 'pages/book2/houses.html' },
  { term: 'Significator', cat: 'Horary', def: 'A planet that stands for a person or matter in the question (e.g. the lord of the 1st for the querent).', see: 'pages/book2/index.html' },
  { term: 'Radical / Radicality', cat: 'Horary', def: 'Whether a figure is "fit to be judged." Tested by the considerations before judgement.', see: 'pages/book2/considerations.html' },
  { term: 'Considerations before Judgement', cat: 'Horary', def: 'Lilly’s cautions for deciding whether a chart is radical — early/late Ascendant, void Moon, Via Combusta, Saturn in the 1st/7th, etc.', see: 'pages/book2/considerations.html' },
  { term: 'Void of Course', cat: 'Horary', def: 'When the Moon makes no further aspect before leaving her sign — "nothing will come of the matter," though she "performs somewhat" in Taurus, Cancer, Sagittarius, Pisces.', see: 'pages/book2/considerations.html' },
  { term: 'Via Combusta', cat: 'Horary', def: 'The "combust way," 15° Libra to 15° Scorpio; Lilly counsels care when the Moon is here.', see: 'pages/book2/considerations.html' },
  { term: 'Perfection', cat: 'Horary', def: 'The completing of a matter — by conjunction or aspect of the significators, or by translation, collection, or reception of light.', see: 'pages/book2/index.html' },
  { term: 'Translation of Light', cat: 'Horary', def: 'A swift planet separates from one significator and applies to the other, carrying virtue between them — often a go-between who brings the matter about.', see: 'pages/book2/index.html' },
  { term: 'Collection of Light', cat: 'Horary', def: 'Two significators that do not aspect each other both apply to a heavier planet which receives them, "collecting" the matter to perfection.', see: 'pages/book2/index.html' },
  { term: 'Reception', cat: 'Horary', def: 'When a planet sits in another’s dignity, it is "received." Mutual reception (each in the other’s dignity) is the strongest help and can perfect a matter through a hard aspect.', see: 'pages/book2/index.html' },
  { term: 'Prohibition', cat: 'Horary', def: 'A third planet perfects an aspect with a significator before the two significators can join, blocking the matter.', see: 'pages/book2/index.html' },
  { term: 'Refranation', cat: 'Horary', def: 'A significator turns retrograde before the awaited aspect completes — the matter "will never be effected."', see: 'pages/book2/index.html' },
  { term: 'Frustration', cat: 'Horary', def: 'A swift planet hastening to a significator is forestalled because that significator joins another planet first.', see: 'pages/book2/index.html' },
  { term: 'Turning the Chart', cat: 'Horary', def: 'Reading a third party’s affairs by treating their house as a new Ascendant (e.g. the 2nd from the 7th = the spouse’s money).', see: 'pages/book2/houses.html' },
  { term: 'Significator', cat: 'Horary', def: 'The planet that stands for a person or matter in a question — the lord of the 1st (and the Moon) for the querent, the lord of the house of the matter for the quesited. The judgement turns on the significators’ condition and how they perfect.', see: 'pages/book2/houses.html' },

  // — Points & special —
  { term: 'Part of Fortune (⊕)', cat: 'Points', def: 'A computed point, Ascendant + Moon − Sun, marking material well-being. Lilly uses the same formula by day and night.', see: 'pages/book2/horary.html' },
  { term: 'Dragon’s Head (☊, North Node)', cat: 'Points', def: 'The Moon’s ascending node; benefic, increasing. Lilly found it equivalent to a fortune.' },
  { term: 'Dragon’s Tail (☋, South Node)', cat: 'Points', def: 'The Moon’s descending node; malefic, diminishing.' },
  { term: 'Antiscion', cat: 'Points', def: 'A point’s "shadow" reflected across the 0° Cancer–0° Capricorn (solstitial) axis; a hidden connection acting like a soft aspect.', see: 'pages/book1/master.html' },
  { term: 'Hyleg (Apheta)', cat: 'Nativities', def: 'The "giver of life" or prorogator in a nativity — the Sun by day or Moon by night in a hylegiacal place, else the Ascendant.', see: 'pages/book3/index.html' },
  { term: 'Alcocoden', cat: 'Nativities', def: 'The "giver of years" — the planet ruling the hyleg’s place, indicating possible length of life by its planetary years.', see: 'pages/book3/index.html' },
  { term: 'Lord of the Geniture', cat: 'Nativities', def: 'The planet with the most essential and accidental dignity in a nativity — the most powerful and predominant influence.', see: 'pages/book3/nativity.html' },
  { term: 'Temperament', cat: 'Nativities', def: 'The humoral balance (choleric, melancholic, sanguine, phlegmatic) of a nativity, judged from the Ascendant, the lights and the season.', see: 'pages/book3/nativity.html' },
  { term: 'Choleric', cat: 'Nativities', def: 'The hot-and-dry humour, of the element Fire and the yellow bile — quick, ardent, irascible in the old physiology. One of the four temperaments Lilly weighs in a nativity (CA Bk III).', see: 'pages/book3/nativity.html' },
  { term: 'Melancholic', cat: 'Nativities', def: 'The cold-and-dry humour, of the element Earth and the black bile — grave, retentive, studious in the old physiology. One of the four temperaments (Lilly CA Bk III).', see: 'pages/book3/nativity.html' },
  { term: 'Sanguine', cat: 'Nativities', def: 'The hot-and-moist humour, of the element Air and the blood — cheerful, sociable, temperate in the old physiology. One of the four temperaments (Lilly CA Bk III).', see: 'pages/book3/nativity.html' },
  { term: 'Phlegmatic', cat: 'Nativities', def: 'The cold-and-moist humour, of the element Water and the phlegm — calm, slow, unhurried in the old physiology. One of the four temperaments (Lilly CA Bk III).', see: 'pages/book3/nativity.html' },
  { term: 'Rectification', cat: 'Nativities', def: 'Correcting an uncertain birth time so the chart agrees with known events or rules. Contested; the Workbench offers the Animodar and the Trutine of Hermes, shown only with their assumptions — never as a measurement.', see: 'pages/book3/master.html' },
  { term: 'Animodar', cat: 'Nativities', def: 'Ptolemy’s rectification (Tetrabiblos III.2): take the almuten of the pre-natal New or Full Moon; the degree it holds within its sign should be the degree of the nearest angle (Ascendant or Midheaven). Contested.', see: 'pages/book3/master.html' },
  { term: 'Trutine of Hermes', cat: 'Nativities', def: 'The Trutina Hermetis: the Moon’s degree at conception equals the Ascendant at birth, and the Ascendant at conception equals the birth Moon (or its opposite), over a ~273-day gestation. Used as a check on the birth time; contested.', see: 'pages/book3/master.html' },
  { term: 'Profection', cat: 'Nativities', def: 'An annual time-lord technique that advances the chart one whole sign for each completed year of life; the ruler of the arrived-at sign becomes the Lord of the Year.', see: 'pages/book3/master.html' },
  { term: 'Profected Sign', cat: 'Nativities', def: 'The whole sign a profection reaches for a given age — the natal Ascendant sign counted forward one sign per completed year.', see: 'pages/book3/master.html' },
  { term: 'Lord of the Year', cat: 'Nativities', def: 'The annual time-lord: the domicile ruler of the profected sign. Its natal condition (dignity, house, aspects) colours the affairs of the year.', see: 'pages/book3/master.html' },
  { term: 'Solar Return (Revolution)', cat: 'Nativities', def: 'The chart for the instant the Sun returns to its exact natal longitude each year — Lilly’s “Revolution”, read as the keynote of the year against the radix.', see: 'pages/book3/master.html' },
  { term: 'Sect Light', cat: 'Nativities', def: 'The luminary that governs a chart by sect — the Sun in a day chart (Sun above the horizon), the Moon in a night chart. It is a primary significator of the native.', see: 'pages/book3/master.html' },
  { term: 'Almuten Figuris', cat: 'Nativities', def: 'The almuten of the WHOLE chart — the planet with the greatest summed essential dignity over the hylegiacal places (Ascendant, Sun, Moon, Part of Fortune, pre-natal syzygy). Identified with the planet of the Perfect Nature; the talisman planet Picatrix III.5 wants matched to the native.', see: 'pages/workbench.html' },
  { term: 'Naibod Key', cat: 'Time', def: 'The rate Valentine Naibod used to turn directional arc into time — the Sun’s mean daily motion, ≈0.9856° of arc per year of life.', see: 'pages/book3/master.html' },
  { term: 'Election (Electional Astrology)', cat: 'Time', def: 'Choosing an auspicious moment to begin an undertaking by casting and weighing charts in advance, so the heavens favour the start. The core method of Picatrix talismanic magic.', see: 'pages/picatrix/election.html' },
  { term: 'Lot / Arabic Part', cat: 'Points', def: 'A computed point found by projecting from the Ascendant the arc between two other points: Lot = Ascendant + (B − C). The Part of Fortune is the best known.', see: 'pages/workbench.html' },
  { term: 'Lot of Spirit', cat: 'Points', def: 'The Hermetic lot complementary to Fortune — Ascendant + Sun − Moon by day (reversed by night). Where Fortune signifies body and circumstance, Spirit signifies mind, will and action.', see: 'pages/workbench.html' },
  { term: 'Lot of Eros', cat: 'Points', def: 'One of the seven Hermetic lots, governing desire and love; built from the Lot of Spirit and Venus (Ascendant + Venus − Spirit by day).', see: 'pages/workbench.html' },
  { term: 'Hermetic Lots', cat: 'Points', def: 'The seven affine points of the Paulus/Hermetic scheme — Fortune, Spirit, Eros, Necessity, Courage, Victory and Nemesis — each computed as Ascendant + A − B and read as a topic-marker. Fortune signifies the body and material life; Spirit its mirror in mind and action; the five planetary lots build from them.', see: 'pages/workbench.html' },
  { term: 'Decumbiture', cat: 'Horary', def: 'A medical chart cast for the moment a patient takes to their bed (or a urine sample is brought), judged for the course and crisis of an illness.', see: 'pages/book2/houses.html' },
  { term: 'Suffumigation', cat: 'Magic', def: 'The fumigation or incense burned in a Picatrix rite — a smoke of herbs, resins and substances proper to a planet (some historical recipes are toxic and recorded for study only).', see: 'pages/picatrix/talisman.html' },
  { term: 'Behenian Fixed Stars', cat: 'Magic', def: 'Fifteen fixed stars of the Hermes/Agrippa canon (Algol, Aldebaran, the Pleiades, Regulus, Spica, etc.) held to carry special virtues for talismans.', see: 'pages/picatrix/stars.html' },
  { term: 'Joys (Planetary)', cat: 'General', def: 'The houses where each planet rejoices and acts most fittingly: Mercury in the 1st, Moon the 3rd, Venus the 5th, Mars the 6th, Sun the 9th, Jupiter the 11th, Saturn the 12th.' },

  // — Time & motion —
  { term: 'Planetary Hours', cat: 'Time', def: 'The division of day and night each into twelve unequal hours, ruled by the planets in the Chaldean order, beginning at sunrise with the lord of the weekday.', see: 'pages/book1/planetary-hours.html' },
  { term: 'Chaldean Order', cat: 'Time', def: 'The planets from slowest to fastest: Saturn, Jupiter, Mars, Sun, Venus, Mercury, Moon — the order of the planetary hours and the faces.' },
  { term: 'Lunar Mansions', cat: 'Magic', def: 'The 28 divisions of the Moon’s monthly path (≈12°51′ each), each with its own magical virtues — central to electional and Picatrix magic.' },
  { term: 'Planetary Prayer (Picatrix)', cat: 'Magic', def: 'The seven invocations of Picatrix III.7 — a Sabian/Harranian rite addressing each planet by its epithets and names in several tongues. Historical text recorded for study, never prescribed.', see: 'pages/picatrix/prayers.html' },
  { term: 'Planetary Spirits (Picatrix)', cat: 'Magic', def: 'The Picatrix III.9 spirit-names (from the Liber Antimaquis): a master spirit per planet plus six directional spirits and a spirit of its motion. Kept distinct from the III.7 prayer-angels and the Agrippa Angel/Intelligence/Spirit triad. Historical doctrine only.', see: 'pages/picatrix/prayers.html' },
  { term: 'Perfect Nature', cat: 'Magic', def: 'Al-Ṭibāʿ al-Tāmm (Picatrix III.6) — the practitioner’s personal celestial guardian or genius, linked to the planet ruling his nativity; invoked by four names (Meegius, Betzahuech, Vacdez, Nufeneguediz). The closest medieval analogue to the later "Holy Guardian Angel." Historical doctrine only.', see: 'pages/picatrix/prayers.html' },

  // — Houses systems —
  { term: 'Regiomontanus', cat: 'Houses', def: "The quadrant house system Lilly used, dividing the celestial equator into equal arcs. This site's default.", see: 'pages/about/index.html#debates' },
  { term: 'Triplicity / Quadruplicity', cat: 'Signs', def: 'Triplicity = the four elemental groups of three signs; quadruplicity = the three modal groups of four (movable, fixed, common).', see: 'pages/book1/reference.html#signs' },

  // — Vedic (Jyotiṣa) — a SEPARATE, sidereal system (Jagannath Hora) —
  { term: 'Sidereal Zodiac', cat: 'Vedic (Jyotiṣa)', def: 'The zodiac measured against the fixed stars rather than the equinox. Vedic astrology is sidereal: a planet’s sidereal longitude = its tropical longitude − the ayanāṁśa. This is the chief computational difference from Lilly’s tropical system.', see: 'pages/vedic/index.html' },
  { term: 'Ayanāṁśa', cat: 'Vedic (Jyotiṣa)', def: 'The accumulated offset between the tropical and sidereal zodiacs from precession (≈24.2° today). This site uses the Lahiri (Citrāpakṣa) ayanāṁśa, the Indian government standard and historic Jagannath Hora default.', see: 'pages/vedic/index.html' },
  { term: 'Rāśi', cat: 'Vedic (Jyotiṣa)', def: 'A sign of the sidereal zodiac (Meṣa/Aries … Mīna/Pisces); also the D1 divisional chart (the rāśi chart). Each rāśi has a planetary lord, as in the Western scheme.', see: 'pages/vedic/index.html' },
  { term: 'Lagna', cat: 'Vedic (Jyotiṣa)', def: 'The Vedic Ascendant — the sidereal degree rising in the east. The 1st bhāva and the foundation of the whole-sign house scheme.', see: 'pages/vedic/index.html' },
  { term: 'Graha', cat: 'Vedic (Jyotiṣa)', def: 'A "seizer" / planet of Jyotiṣa — the seven of Lilly plus the two lunar nodes Rāhu and Ketu (the navagraha, nine grahas).', see: 'pages/vedic/index.html' },
  { term: 'Nakṣatra', cat: 'Vedic (Jyotiṣa)', def: 'One of the 27 lunar mansions (13°20′ each) of the sidereal zodiac, each ruled by a graha and a deity. The Moon’s nakṣatra seeds the Vimśottarī daśā. (Distinct from the Picatrix’s 28 lunar mansions.)', see: 'pages/vedic/index.html' },
  { term: 'Pada', cat: 'Vedic (Jyotiṣa)', def: 'A "quarter" — one of the four 3°20′ sub-divisions of a nakṣatra, mapping to a navāṁśa sign.', see: 'pages/vedic/index.html' },
  { term: 'Vimśottarī Daśā', cat: 'Vedic (Jyotiṣa)', def: 'The principal Vedic timing system: a 120-year cycle of planetary periods (mahādaśā) and sub-periods (antardaśā), apportioned from the Moon’s birth nakṣatra. The running daśā lord colours the period.', see: 'pages/vedic/index.html' },
  { term: 'Pañcāṅga', cat: 'Vedic (Jyotiṣa)', def: 'The "five limbs" of the Vedic almanac for a moment: tithi (lunar day), vāra (weekday), nakṣatra, yoga and karaṇa — the basis of muhūrta (Vedic election).', see: 'pages/vedic/index.html' },
  { term: 'Tithi', cat: 'Vedic (Jyotiṣa)', def: 'A lunar day — one of 30 in a synodic month, each 12° of Moon-minus-Sun elongation; waxing (śukla) or waning (kṛṣṇa).', see: 'pages/vedic/index.html' },
  { term: 'Vāra', cat: 'Vedic (Jyotiṣa)', def: 'The weekday and its ruling graha — the same Chaldean weekday-lord scheme as Lilly’s planetary days, and the anchor of the day’s traditional observance (vrata) and mantra.', see: 'pages/vedic/index.html' },
  { term: 'Varga', cat: 'Vedic (Jyotiṣa)', def: 'A divisional (harmonic) chart, Dn, that re-maps each sign into n parts to examine a life area — D9 navāṁśa (marriage/dharma), D10 daśāṁśa (career), etc. This site computes D1–D60.', see: 'pages/vedic/index.html' },
  { term: 'Navāṁśa', cat: 'Vedic (Jyotiṣa)', def: 'The D9 varga (ninth-divisions): the most-used divisional chart, read for marriage, dharma and the inner strength of each graha.', see: 'pages/vedic/index.html' },
  { term: 'Aṣṭakavarga', cat: 'Vedic (Jyotiṣa)', def: 'A bindu (point) scoring system: each graha contributes benefic points to the signs, giving its Bhinnāṣṭakavarga; summed across grahas it gives the Sarvāṣṭakavarga (SAV), whose grand total is always 337.', see: 'pages/vedic/index.html' },
  { term: 'Ṣaḍbala', cat: 'Vedic (Jyotiṣa)', def: 'The "six-fold strength" of a graha — Sthāna (positional), Dig (directional), Kāla (temporal), Ceṣṭā (motional), Naisargika (natural) and Dṛk (aspectual) bala, summed in rūpas and weighed against a required minimum. (BPHS Ch. 27.)', see: 'pages/vedic/index.html' },
  { term: 'Bhāva', cat: 'Vedic (Jyotiṣa)', def: 'A Vedic house. This site uses whole-sign bhāvas: the Lagna’s whole sign is the 1st, the next sign the 2nd, and so on.', see: 'pages/vedic/index.html' },
  { term: 'Kāraka', cat: 'Vedic (Jyotiṣa)', def: 'A natural significator — each graha "shows" certain matters (the Sun the soul and father, Jupiter wisdom and children, Venus love and art, etc.).', see: 'pages/vedic/index.html' },
  { term: 'Bīja Mantra', cat: 'Vedic (Jyotiṣa)', def: 'A "seed" mantra — a tāntric syllable-formula addressed to a graha (e.g. Oṁ Hrāṁ Hrīṁ Hrauṁ Saḥ Sūryāya Namaḥ for the Sun). Recorded here as historical/cultural practice, never prescribed.', see: 'pages/vedic/index.html' },
  { term: 'Yantra', cat: 'Vedic (Jyotiṣa)', def: 'A geometric diagram — for the grahas, a planetary magic square (the Sun’s is the 3×3 summing to 15; each graha’s constant steps by 3). Recorded as cultural practice, not prescribed.', see: 'pages/vedic/index.html' },

  // — Geomancy (ʿilm al-raml) —
  { term: 'Geomancy', cat: 'Geomancy', def: 'ʿilm al-raml, "the science of the sand" — a divinatory art (Agrippa called it the "daughter of astrology") in which four randomly-cast figures generate, by pure algebra, a whole Shield Chart that is then judged. A historical art of no demonstrated validity.', see: 'pages/geomancy.html' },
  { term: 'Geomantic Figure', cat: 'Geomancy', def: 'One of sixteen tetragrams — four lines, each a single (·) or double (:) point (head/neck/body/feet = fire/air/water/earth). The sixteen are exactly the 2⁴ patterns, each with a planet, sign, element and meaning.', see: 'pages/geomancy.html' },
  { term: 'Shield Chart', cat: 'Geomancy', def: 'The geomantic figure: four Mothers (cast at random) generate four Daughters (by transposition), four Nieces, two Witnesses, a Judge and a Reconciler — every one derived by line-by-line parity addition.', see: 'pages/geomancy.html' },
  { term: 'Mothers, Daughters & Nieces', cat: 'Geomancy', def: 'The first twelve figures of the Shield. The four Mothers are cast; the Daughters are read columnwise from the Mothers; each Niece is the parity-sum of two figures above it.', see: 'pages/geomancy.html' },
  { term: 'Witnesses & Judge', cat: 'Geomancy', def: 'The Right Witness (the querent / the past) and Left Witness (the quesited / what follows) add to the Judge, which gives the outcome. The Judge always has an even number of points — geomancy’s built-in checksum.', see: 'pages/geomancy.html' },
  { term: 'Reconciler (Geomancy)', cat: 'Geomancy', def: 'An optional clarifying figure, the parity-sum of the Judge and the first Mother, read when the Judge is doubtful.', see: 'pages/geomancy.html' },
  { term: 'Perfection (Geomancy)', cat: 'Geomancy', def: 'Whether the querent’s and quesited’s figures truly meet in the House Chart — by occupation (sharing a house), conjunction (lying adjacent), mutation, or translation (a third figure carrying between them).', see: 'pages/geomancy.html' },
  { term: 'House Chart (Geomancy)', cat: 'Geomancy', def: 'The twelve generated figures laid into the twelve astrological houses (Mothers 1–4, Daughters 5–8, Nieces 9–12) and read by the house the question falls under, exactly as in horary.', see: 'pages/geomancy.html' },

  // — Tarot —
  { term: 'Tarot', cat: 'Tarot', def: 'A 78-card deck used for cartomancy in the Rider–Waite–Smith / Golden Dawn tradition: 22 Major Arcana and 56 Minor Arcana in four suits. A historical divinatory art of no demonstrated validity; its correspondences are a late-Victorian synthesis.', see: 'pages/tarot.html' },
  { term: 'Major Arcana', cat: 'Tarot', def: 'The 22 trump cards (0 The Fool – XXI The World), each carrying a Golden Dawn Hebrew-letter and astrological attribution. A preponderance of them in a spread is read as great, fated forces at work.', see: 'pages/tarot.html' },
  { term: 'Minor Arcana', cat: 'Tarot', def: 'The 56 suit cards: Wands (Fire), Cups (Water), Swords (Air), Pentacles (Earth), each Ace–Ten plus the four Court Cards (Page, Knight, Queen, King).', see: 'pages/tarot.html' },
  { term: 'Court Cards', cat: 'Tarot', def: 'The sixteen Page, Knight, Queen and King cards — read as people, or as the elemental sub-aspect of their suit (e.g. the Queen of Cups = the watery part of Water).', see: 'pages/tarot.html' },
  { term: 'Elemental Dignities', cat: 'Tarot', def: 'The Golden Dawn rule by which adjacent cards modify one another by element: like reinforces like; Fire+Air and Water+Earth are friendly (strengthen); Fire+Water and Air+Earth are contrary (weaken).', see: 'pages/tarot.html' },
  { term: 'Reversal (Tarot)', cat: 'Tarot', def: 'A card dealt upside-down, read by many (esp. post-Golden Dawn) as a blocked, weakened, internalised or shadow form of its upright meaning — a dimmer-switch, not automatically a negation. Some traditions ignore orientation.', see: 'pages/tarot.html' },
  { term: 'Celtic Cross', cat: 'Tarot', def: 'A. E. Waite’s famous ten-card spread: a cross of six (the situation, its crossing, foundation, past, crown and near future) and a staff of four (the querent, environment, hopes & fears, and outcome).', see: 'pages/tarot.html' },
  { term: 'Significator (Tarot)', cat: 'Tarot', def: 'A card chosen to stand for the querent or the matter at the centre of a spread (in the Celtic Cross, the first card, which the crossing card covers).', see: 'pages/tarot.html' },

  // — I Ching (the Book of Changes) —
  { term: 'I Ching', cat: 'I Ching', def: 'The Yijing, the Book of Changes — a Chinese divinatory classic that answers a question with a hexagram cast at the moment of asking. A historical art of no demonstrated validity; the structure is exact mathematics, the meanings are the tradition’s.', see: 'pages/iching.html' },
  { term: 'Hexagram', cat: 'I Ching', def: 'One of the 64 figures of six lines (each yin/broken or yang/solid), read bottom to top — the lower trigram beneath the upper. The 64 are exactly the 2⁶ combinations, numbered in the King Wen sequence.', see: 'pages/iching.html' },
  { term: 'Trigram', cat: 'I Ching', def: 'One of the eight three-line figures (bagua) — Heaven, Lake, Fire, Thunder, Wind, Water, Mountain, Earth — from which the hexagrams are built (an upper over a lower trigram).', see: 'pages/iching.html' },
  { term: 'Moving (Changing) Lines', cat: 'I Ching', def: 'Lines cast as "old" (old yin 6 or old yang 9) rather than "young" (7, 8). They are the pivots of the reading, and flipping them to their opposite yields the relating hexagram.', see: 'pages/iching.html' },
  { term: 'Relating Hexagram', cat: 'I Ching', def: 'The second hexagram obtained by flipping every moving line of the primary — the direction the situation tends toward.', see: 'pages/iching.html' },
  { term: 'Nuclear Hexagram', cat: 'I Ching', def: 'The inner hexagram built from the middle lines of the primary (lines 2–4 as the lower, 3–5 as the upper) — read as the hidden core of the matter.', see: 'pages/iching.html' },
  { term: 'King Wen Sequence', cat: 'I Ching', def: 'The traditional order of the 64 hexagrams (1 The Creative, 2 The Receptive, … 64 Before Completion), attributed to King Wen of Zhou.', see: 'pages/iching.html' },

  // — Jung & astrology —
  { term: 'Synchronicity', cat: 'Jung', def: 'Jung’s "acausal connecting principle" (1952): a meaningful coincidence between an inner, psychic state and an outer event, connected by meaning rather than cause. Jung classed astrology’s apparent hits here — not as astral causation.', see: 'pages/jung/theory.html' },
  { term: 'Archetype', cat: 'Jung', def: 'In Jung’s psychology, an inherited, formal disposition of the collective unconscious that shapes images and behaviour — the planetary "gods" of astrology being, on his reading, archetypal images projected onto the sky.', see: 'pages/jung/theory.html' },
  { term: 'Collective Unconscious', cat: 'Jung', def: 'Jung’s stratum of the psyche common to humankind, the home of the archetypes; astrology, he argued, is the psychology of antiquity written into the heavens by projection.', see: 'pages/jung/theory.html' },
  { term: 'Anima / Animus', cat: 'Jung', def: 'Jung’s contra-sexual soul-images: the inner feminine of a man’s psyche (anima) and inner masculine of a woman’s (animus). Astrologically the era-bound scheme read the anima through Moon and Venus, the animus through Sun and Mars.', see: 'pages/jung/tool.html' },
  { term: 'Individuation', cat: 'Jung', def: 'Jung’s name for the life-long integration of the personality around the Self — imaged in alchemy (and in a chart-reading after him) by the Sol–Luna coniunctio, the union of conscious and unconscious.', see: 'pages/jung/theory.html' },
  { term: 'Coniunctio', cat: 'Jung', def: 'The alchemical "marriage" of Sol and Luna that Jung (Mysterium Coniunctionis) read as the great image of psychic union — the very motif his marriage experiment’s Sun–Moon aspects embody.', see: 'pages/jung/tool.html' },
  { term: 'Synastry', cat: 'Jung', def: 'Chart-comparison: the aspects computed BETWEEN two nativities. Jung’s 1952 experiment tallied fifty cross-aspects — the conjunctions and oppositions of Sun, Moon, Mars, Venus and the Ascendant–Descendant axis between spouses (the MC/IC deliberately omitted — CW 8 §878 n. 3).', see: 'pages/jung/tool.html' },
  { term: 'Platonic Month (Aeon)', cat: 'Jung', def: 'One twelfth of the ~25,800-year precessional cycle — ≈ 2,148 years, the time the vernal point takes to cross one sign. Jung’s Aion reads the Christian aeon against the vernal point’s passage through Pisces.', see: 'pages/jung/tool.html' },
  { term: 'Age of Pisces / Aquarius', cat: 'Jung', def: 'The precessional "ages". There is no fact about when one ends: Jung himself put the beginning of the next aeon "between AD 2000 and AD 2200", depending on the starting point selected (Aion, n. to §149); the equal-sign sidereal reckoning gives ≈ 2440, the IAU constellation boundary ≈ 2600. The precession is real; the boundaries are conventions.', see: 'pages/jung/tool.html' },
  { term: 'Marriage Experiment (Jung)', cat: 'Jung', def: 'Jung’s one formal statistical test of astrology (Synchronicity, CW 8): 483 married pairs, 50 cross-aspects. The classic marriage aspects topped each batch — at rates chance alone produces, as the Fierz correction showed and Jung conceded.', see: 'pages/jung/experiment.html' },

  // — Kameas & sigils —
  { term: 'Kamea (Magic Square)', cat: 'Picatrix & Magic', def: 'A planetary "table": an n×n square of the numbers 1…n² whose every row, column and diagonal sums alike (Saturn 3×3 to the Moon 9×9, Agrippa II.22). Real, checkable mathematics that the tradition read as the planets’ divine numbers and engraved as talismans.', see: 'pages/picatrix/kameas.html' },
  { term: 'Sigil', cat: 'Picatrix & Magic', def: 'A character formed by tracing a name, letter by letter, through the cells of a kamea — a circle where the line begins, a bar where it ends. The historical method worked on Hebrew names via gematria (Agrippa III.30).', see: 'pages/picatrix/kameas.html' },
  { term: 'Aiq Bekar (Nine Chambers)', cat: 'Picatrix & Magic', def: 'The kabbalistic reduction that lays the Hebrew alphabet on nine "chambers" — units 1–9, tens 10–90, hundreds 100–900 — so any letter-value collapses into the range of a square (300 → 3). The key Agrippa leaves for deriving sigils from the kameas.', see: 'pages/picatrix/kameas.html' },
  { term: 'Intelligence & Spirit (of a planet)', cat: 'Picatrix & Magic', def: 'The paired names Agrippa assigns each planet — the Intelligence its benevolent mover, the Spirit its raw daemon — with gematria values keyed to the planet’s square (e.g. the Sun: Nachiel 111, the line-sum; Sorath 666, the total).', see: 'pages/picatrix/kameas.html' },

  // — The Hermetic Chronology wing —
  { term: 'Hermetica', cat: 'Chronology', def: 'The body of Greek (and some Latin/Coptic) treatises attributed to Hermes Trismegistus, written in Roman Egypt c. 100–300 CE — philosophical dialogues teaching gnosis: rebirth, the soul\'s ascent, and union with the divine Mind.', see: 'pages/chronology/hermetica.html' },
  { term: 'Corpus Hermeticum', cat: 'Chronology', def: 'The collection of seventeen Greek Hermetic treatises (CH I is the Poimandres) recovered for the West when a codex reached Florence in 1460 and Ficino translated it in 1463. Casaubon showed in 1614 that the texts are early-CE, not primordially ancient.', see: 'pages/chronology/hermetica.html' },
  { term: 'Hermes Trismegistus', cat: 'Chronology', def: '"Thrice-greatest Hermes" — the legendary sage produced by fusing the Greek god Hermes with the Egyptian Thoth (attested by the 1st c. CE). Not a historical person: the name under which the Hermetica, the Emerald Tablet and much alchemy travelled.', see: 'pages/chronology/index.html' },
  { term: 'Emerald Tablet (Tabula Smaragdina)', cat: 'Chronology', def: 'The terse alchemical text behind the maxim "as above, so below" — first attested in Arabic works of the 8th–9th c. (Pseudo-Apollonius), Latin from the 12th c. Its discovery in Hermes\'s tomb is myth, not history.', see: 'pages/chronology/index.html' },
  { term: 'Epistemic label (documented / disputed / debunked / conspiracy)', cat: 'Chronology', def: 'The Chronology wing\'s honesty device: every timeline entry is tagged documented (primary texts or peer-reviewed scholarship), disputed (contested among scholars), debunked (disproven by verifiable evidence) or conspiracy (no evidentiary basis; shown as discourse, not fact).', see: 'pages/chronology/index.html' },
  { term: 'Magnum opus (the Great Work)', cat: 'Chronology', def: 'Alchemy\'s complete process toward the Philosophers\' Stone, described through colour-stages — nigredo (blackening), albedo (whitening), citrinitas (yellowing), rubedo (reddening) — a circle, not a ladder. Transmutation was never demonstrated; the labour built real chemistry.', see: 'pages/chronology/alchemy.html' },
  { term: 'Prima materia', cat: 'Chronology', def: 'The "first matter" of alchemy — the formless base substance the adept must find and reduce, from which the Stone is built; described through dozens of deliberate cover-names (Decknamen) rather than a single ingredient.', see: 'pages/chronology/alchemy.html' },
  { term: 'Grimoire', cat: 'Chronology', def: 'A manual of ritual magic. The Latin tradition (Sworn Book of Honorius, Key of Solomon, the 17th-c. Lemegeton) wove Solomonic, astrological and Christian elements together and was inherited and reworked by the modern magical orders.', see: 'pages/chronology/index.html' },

  // — Cycles of History —
  { term: 'Great Conjunction', cat: 'Cycles', def: 'A Jupiter–Saturn conjunction — the slowest naked-eye planetary cycle, one every ~19.86 years. Medieval mundane astrology (Abū Maʿshar) made it the clock of world history; the 2020 conjunction (0°29′ Aquarius, minimum separation 6.1′) was the closest since 1623.', see: 'pages/cycles.html' },
  { term: 'Trigon (Triplicity shift)', cat: 'Cycles', def: 'Successive great conjunctions fall ~120° apart, tracing Kepler’s slowly rotating triangle and staying ~10–12 conjunctions (~220 years; doctrinally 240) in one elemental triplicity before shifting to the next. The doctrine made the shift signify religious and dynastic change — a documented belief, no validity demonstrated.', see: 'pages/cycles.html' },
  { term: 'Saros / 223 months', cat: 'Cycles', def: 'The 223-synodic-month eclipse cycle Late Babylonian astronomers used to predict eclipse POSSIBILITIES — possibility, never certainty of local visibility. After 223 months the Sun–Moon–node geometry nearly repeats. The name “Saros” is an 18th-century misnomer; the texts simply count 223 months.', see: 'pages/cycles.html' },
  { term: 'Ecliptic limits', cat: 'Cycles', def: 'How far from a lunar node a new/full moon may fall and still yield an eclipse somewhere on Earth: solar — certain under 15.39°, impossible over 18.59°; lunar (any type incl. penumbral) 15.3°–17.1°; classical umbral lunar 9°30′/12°15′ (NASA/Espenak). Between the bounds an eclipse is only “possible”.', see: 'pages/cycles.html' },
  { term: 'Eclipse season', cat: 'Cycles', def: 'The window, twice a year, when the Sun stands near a lunar node and eclipses become possible: it takes the Sun ~34.5 days to cross the 34°-wide eclipse zone centred on each node, so every eclipse season contains at least one solar eclipse.', see: 'pages/cycles.html' },
  { term: 'Mean vs true conjunction', cat: 'Cycles', def: 'The medieval doctrine ran on MEAN conjunctions — an idealized clock ticking exactly every 19.859 Julian years, +242.98° (tropical) per tick, never triple. The observed GEOCENTRIC conjunction in apparent longitude can be single or triple (retrogradation near opposition: 7 BCE, 1940–41, 1980–81; next 2238–39). The divergence between clock and sky is the tool’s teaching point.', see: 'pages/cycles.html' },

  // — Time-lords (pages/timelords.html) —
  { term: 'Time-lord', cat: 'Time-lords', def: 'A planet (or sign) said to "rule" a stretch of a life in the classical timing doctrines — profections, firdaria, zodiacal releasing, decennials. A historical convention, not a validated claim.', see: 'pages/timelords.html' },
  { term: 'Secondary Progressions', cat: 'Time-lords', def: 'The day-for-a-year time-map: the sky N days after birth stands for the native’s Nth year (classical statement: Valens, Anthology IX.3). Planets are read from the real ephemeris at birth + age-in-days (tropical years); this site progresses the angles by the Naibod arc only.', see: 'pages/timelords.html' },
  { term: 'Day-for-a-Year', cat: 'Time-lords', def: 'The symbolic equation behind secondary progressions — one ephemeris day after birth ≡ one year of life ("add a number of days… equivalent to the age of the native" — Valens IX.3). Its modern formalization is conventionally credited to Placidus, with Salmasius a rival claimant.', see: 'pages/timelords.html' },
  { term: 'Naibod Arc', cat: 'Time-lords', def: 'The accumulated arc of the Sun’s MEAN daily motion — 360°/365.2422 = 0.98564733° = 59′08″ per year of life (Valentin Naibod, 16th c.) — used here to progress the MC, with the Ascendant re-derived through the birth latitude. See also the Naibod Key (the same rate, used in primary directions).', see: 'pages/timelords.html' },
  { term: 'Firdaria', cat: 'Time-lords', def: 'The Persian planetary periods (al-firdārāt): a repeating 75-year cycle — by day Sun 10, Venus 8, Mercury 13, Moon 9, Saturn 11, Jupiter 12, Mars 7, then the nodes 3 + 2; night births start from the Moon. Each planetary period splits into 7 equal sub-periods, the first ruled by the period lord. The night-chart node placement is DISPUTED (Abu Maʿshar: at the end; Bonatti: after Mars) and this site shows both.', see: 'pages/timelords.html' },
  { term: 'Zodiacal Releasing', cat: 'Time-lords', def: 'Valens’s time-lord system (Anthology IV): periods "released" sign by sign from the Lot of Spirit (action/career) or Fortune (body), each sign lasting its ruler’s minor years (Capricorn 27, not 30), counted in 360-day years and 30-day months; sub-periods start from the parent’s own sign.', see: 'pages/timelords.html' },
  { term: 'Loosing of the Bond', cat: 'Time-lords', def: 'In zodiacal releasing: when a subdivision completes all 12 signs, the 13th sub-period does not repeat the start sign but JUMPS to the opposite sign (R. Schmidt’s term; Valens IV.4). Possible only inside L1 signs with 19 or more years — Gemini, Cancer, Leo, Virgo, Capricorn, Aquarius.', see: 'pages/timelords.html' },
  { term: 'Distribution Year (360-day)', cat: 'Time-lords', def: 'Valens’s releasing clock (Anthology IV.9): "the universal year has 365¼ days, while the year with respect to the distribution has 360" — so releasing boundaries drift against calendar years. His own check: 11,903 days lived = 33 distribution-years + 23 days.', see: 'pages/timelords.html' },

  // — Praśna & KP (Indian horary) —
  { term: 'Praśna', cat: 'Indian horary', def: 'Indian horary astrology: a question judged from the sidereal chart of the moment it is asked. The praśna lagna is the querent, read exactly as a birth lagna (Praśna Mārga I.47); the Moon is the querent’s mind and its house is itself a testimony. A historical art of no demonstrated validity.', see: 'pages/prasna.html' },
  { term: 'KP (Krishnamurti Paddhati)', cat: 'Indian horary', def: 'K. S. Krishnamurti’s 20th-century system: each nakṣatra is cut into nine sub-arcs proportional to the Vimśottarī daśā years, and the sub-lord — especially of a house cusp — is the claimed “final judge” of the matter. Its 249-entry horary table is self-verifiable arithmetic inside a divinatory convention.', see: 'pages/prasna.html' },
  { term: 'Sub-lord', cat: 'Indian horary', def: 'The lord of the sub-arc a sidereal longitude falls in. Within each 13°20′ nakṣatra the nine subs run in Vimśottarī order starting from the nakṣatra’s own lord, each spanning years × 400″ of arc (Ketu 46′40″ … Venus 2°13′20″); the chain reads sign lord → star lord → sub-lord.', see: 'pages/prasna.html' },
  { term: 'Horary number (KP)', cat: 'Indian horary', def: 'The number 1–249 the QUERENT (not the astrologer) picks; it indexes the sub-arcs zodiacally from 0° sidereal Aries and fixes the praśna ascendant in that sub (No. 1 = 0° Aries, Ketu/Ketu; No. 249 = the last sub of Revatī). From KP Reader VI, “Horary Astrology”.', see: 'pages/prasna.html' },
  { term: 'Kendra', cat: 'Indian horary', def: 'The four “angle” houses 1, 4, 7 and 10 of the whole-sign chart (the trikoṇas are 5 and 9). Praśna’s core configuration wants benefics in kendras/trikoṇas and malefics in 3, 6 and 11 — and NOT in the angles or the 8th (the exclusion clause of Daivajña Vallabha II.20/21).', see: 'pages/prasna.html' },
  { term: 'Ārūḍha', cat: 'Indian horary', def: 'In praśna, the sign of the compass direction the querent faces at the consultation (Praśna Mārga II.7–11; a circle-touch fallback exists). An external physical datum — computable only when supplied, never inferred; houses are then reckoned from ārūḍha or lagna, whichever is stronger (PM IX.29).', see: 'pages/prasna.html' },

  // — Muhūrta (Indian electional) —
  { term: 'Muhūrta', cat: 'Muhūrta', def: 'One thirtieth of the sunrise-to-sunrise day in Indian electional astrology: the daylight arc and the night arc each divide into 15 named, classically graded parts (≈48 min on a mean day) — and, by extension, the art of electing the moment by them.', see: 'pages/muhurta.html' },
  { term: 'Abhijit muhūrta', cat: 'Muhūrta', def: 'The 8th of the 15 day-muhūrtas; its midpoint is always the mid-day point (sunrise + half the day arc — local apparent noon). Traditionally the default-auspicious window, said to destroy doṣas; its weekday exception is contested (Mon/Fri in the table sources vs Wednesday per drikpanchang), flagged in-data.', see: 'pages/muhurta.html' },
  { term: 'Brāhma muhūrta', cat: 'Muhūrta', def: 'The 29th of the 30 muhūrtas — from two night-muhūrtas before sunrise to one before (04:24–05:12 on a mean day): the pre-dawn window the tradition grades "very auspicious" and reserves for study and practice.', see: 'pages/muhurta.html' },
  { term: 'Rāhu-kāla', cat: 'Muhūrta', def: 'The avoided eighth of the daylight arc assigned to Rāhu, picked by the weekday (Sun 8th, Mon 2nd, Tue 7th, Wed 5th, Thu 6th, Fri 4th, Sat 3rd octant from sunrise). One of the three daily kālas, with Yamaghaṇṭa and Gulika-kāla.', see: 'pages/muhurta.html' },
  { term: 'Gulika-kāla', cat: 'Muhūrta', def: "The eighth of the daylight arc belonging to Saturn: give the day's eight parts lords starting from the weekday's ruler in weekday order (the eighth part lordless) — Gulika is Saturn's part (Sun 7th … Sat 1st). Classically avoided.", see: 'pages/muhurta.html' },
  { term: 'Pañcāṅga', cat: 'Muhūrta', def: "The 'five limbs' of the Indian calendar day — tithi (lunar day), vāra (the weekday, beginning at sunrise), nakṣatra (the Moon's mansion), yoga (Sun+Moon sum) and karaṇa (half-tithi) — the raw material of every muhūrta screen.", see: 'pages/muhurta.html' },

  // — Matching (guṇa-milāpa / porutham) —
  { term: 'Tithi-praveśa', cat: 'Matching', def: "The Vedic annual (or monthly) return chart, cast for the instant the Moon regains its exact natal elongation from the Sun — the same tithi and tithi-fraction — while the Sun is back in its natal sidereal sign. Rath's Odiśā tradition; a modern-lineage technique with no classical BPHS anchor (flagged); the solar/soli-lunar month rule is contested.", see: 'pages/tithi-pravesha.html' },
  { term: 'Aṣṭakūṭa', cat: 'Matching', def: "The North-Indian eight-kūṭa (36-guṇa) marriage-matching score computed from two Moons' nakṣatra and rāśi: varṇa 1, vaśya 2, tārā 3, yoni 4, graha-maitrī 5, gaṇa 6, bhakūṭa 7, nāḍī 8. A cultural custom of no demonstrated validity — what the tradition computes, never advice.", see: 'pages/kuta.html' },
  { term: 'Nāḍī doṣa', cat: 'Matching', def: 'The heaviest single kūṭa (8 points): when both Moons fall in the same nāḍī (Ādi / Madhya / Antya pulse-group) the score is 0 (nāḍī-doṣa). Cancellation rules and the exempt-star lists vary by source (two distinct lists circulate) — displayed, never resolved.', see: 'pages/kuta.html' },
  { term: 'Bhakūṭa', cat: 'Matching', def: 'The rāśi kūṭa (7 points): zeroed (bhakūṭa-doṣa) when the two Moon-signs stand 2/12, 5/9 or 6/8 apart. The doṣa is held cancelled by same or friendly rāśi lords; whether the points are restored is itself disputed. Note the South rāśi porutham calls 5/9 GOOD — a cross-system contradiction shown both ways.', see: 'pages/kuta.html' },
  { term: 'Rajju', cat: 'Matching', def: "A South-Indian porutham veto: the 27 nakṣatras map to five body-groups (pāda/foot, kaṭi/waist, nābhi/navel, kaṇṭha/neck, śiras/head). Two stars in the SAME rajju reject the pairing in the strict Tamil rule, each group carrying a traditional (belief, not fact) consequence.", see: 'pages/kuta.html' },
  { term: 'Vedhā', cat: 'Matching', def: 'A South-Indian porutham veto: twelve mutually-afflicting nakṣatra pairs plus the {Mṛgaśīrṣa, Citrā, Dhaniṣṭhā} triple cover all 27 stars; any vedhā match rejects the pairing.', see: 'pages/kuta.html' },

  // — Tājika (the Indo-Persian annual chart) —
  { term: 'Varṣaphala', cat: 'Tājika', def: 'The "fruit of the year": the Indo-Persian (Tājika) annual-chart system of Jyotiṣa — a chart cast for each year of life at the sidereal solar return, read through the munthā, the varṣeśvara, Tājika aspects and the sahams. Its grammar is Sanskritized Arabic (13th c., Samarasiṃha).', see: 'pages/tajika.html' },
  { term: 'Varṣa-praveśa', cat: 'Tājika', def: 'The "entry of the year": the instant the Sun regains its natal SIDEREAL longitude — the sidereal solar return, falling ≈20 minutes later than the tropical return per year of age. The annual chart is cast for this moment.', see: 'pages/tajika.html' },
  { term: 'Munthā', cat: 'Tājika', def: 'The progressed year-sign: the natal ascendant sign advanced one sign per completed year of age ((natal Asc sign + completed years) mod 12), moving ≈2.5°/month within the year. Its house in the annual chart sets the year’s focus.', see: 'pages/tajika.html' },
  { term: 'Varṣeśvara', cat: 'Tājika', def: 'The ruler of the year, chosen from five candidates (munthā lord, natal-lagna lord, annual-lagna lord, the Tājika triplicity lord of the annual lagna, the Sun-sign lord by day / Moon-sign lord by night). The precondition is an aspect to the annual lagna; when none aspects, the authorities split four ways — a documented dispute.', see: 'pages/tajika.html' },
  { term: 'Itthaśāla', cat: 'Tājika', def: 'The applying configuration (Arabic ittiṣāl): the swifter planet behind the slower within the orbs of light, in a Tājika aspect — the same applying doctrine Lilly’s horary uses. Past exactness by under 1° still counts, per "the ancient commentator".', see: 'pages/tajika.html' },
  { term: 'Īsarāpha', cat: 'Tājika', def: 'The separating configuration (Arabic inṣirāf): the swifter planet a full degree or more past exactness (Tājikabhūṣaṇa 4.10) — held to dissolve or deny the matter.', see: 'pages/tajika.html' },
  { term: 'Saham', cat: 'Tājika', def: 'A Tājika lot (Arabic sahm): minuend − subtrahend + added point (usually the Lagna), minuend and subtrahend swapping at night unless stated, with +30° when the added point falls outside the arc from subtrahend to minuend — a correction Viśvanātha’s Prakāśikā (1629) rejected outright.', see: 'pages/tajika.html' },
  { term: 'Deeptāṁśa', cat: 'Tājika', def: 'The "orbs of light" bounding Tājika configurations: Sun 15°, Moon 12°, Mars 8°, Mercury 7°, Jupiter 9°, Venus 7°, Saturn 9° (Daivajñālaṃkṛti 8.9 = Tājikasāra 88; Rāhu 12° only in the Praśnavaiṣṇava).', see: 'pages/tajika.html' },

  // — Kabbalah —
  { term: 'Sephiroth', cat: 'Kabbalah', def: 'The ten "emanations" of the medieval kabbalistic tree (Kether … Malkuth). The Sefer Yetzirah itself knows ten "sefirot belimah" as abstract numbers only; the named scheme is medieval (Bahir c. 1176, Zohar c. 1286). Seven carry planets in the Golden Dawn ladder (Binah=Saturn … Yesod=Moon); Kether, Chokmah and Malkuth are NOT planets.', see: 'pages/kabbalah.html' },
  { term: 'Tree of Life (Kircher layout)', cat: 'Kabbalah', def: 'The 10-sephiroth / 22-path diagram as printed by Athanasius Kircher (Oedipus Aegyptiacus II, 1652–54) and adopted by the Golden Dawn. Lurianic/Gra trees route paths differently and do not support the GD letter table; the earliest printed tree (1516) had only 17 paths.', see: 'pages/kabbalah.html' },
  { term: 'The 22 Paths', cat: 'Kabbalah', def: 'The channels joining the sephiroth, numbered 11–32, one per Hebrew letter — 3 mothers (elements), 7 doubles (planets — the assignment is contested between recensions), 12 simples (zodiac signs) — each with a Golden Dawn tarot trump.', see: 'pages/kabbalah.html' },
  { term: 'The Three Pillars', cat: 'Kabbalah', def: 'The tree’s columns: Mercy (2,4,7 — the viewer’s right in the diagram convention), Severity (3,5,8 — viewer’s left) and the Middle Pillar (1,6,9,10). Some texts name left/right from the Tree’s own "body," reversing the labels — the convention must be stated.', see: 'pages/kabbalah.html' },
  { term: 'Gematria', cat: 'Kabbalah', def: 'Letter-arithmetic: each Hebrew letter has a numeric value (Aleph 1 … Tau 400) and a word’s value is the sum — e.g. echad "one" = 13, ahavah "love" = 13, chai "life" = 18, YHVH = 26. The sums are exact; the meaning read into equal sums is the tradition’s, of no demonstrated validity.', see: 'pages/kabbalah.html' },
  { term: 'Mispar gadol', cat: 'Kabbalah', def: 'The gematria VARIANT that gives the five final letter-forms their own values (ך 500, ם 600, ן 700, ף 800, ץ 900). Standard counting (mispar hechrachi) values finals the same as their medial forms — the variant is flagged, never the default.', see: 'pages/kabbalah.html' },
  { term: 'Sefer Yetzirah', cat: 'Kabbalah', def: 'The "Book of Formation" — a short Hebrew cosmological tract deriving creation from 10 numbers and the 22 letters (3 mothers / 7 doubles / 12 simples). Survives in three recensions (Short, Long, Saadia) plus the later Gra redaction; dating unresolved (2nd–9th-c. proposals; first firm attestation the 10th-c. commentaries).', see: 'pages/kabbalah.html' },
  { term: 'Daath', cat: 'Kabbalah', def: 'The "hidden" quasi-sephirah at the Abyss — NOT one of the ten. Absent from Kircher and Agrippa; first drawn by Knorr von Rosenroth (Kabbala Denudata, 1677–84). Its 20th-c. outer-planet attributions are unsettled and never adopted here.', see: 'pages/kabbalah.html' },

  // — Runes (Elder Futhark) —
  { term: 'Elder Futhark', cat: 'Runes', def: 'The oldest runic alphabet — 24 staves used to write the Germanic languages roughly c. 150–700/800 CE. First and foremost a WRITING system; every per-rune "divinatory meaning" is a 20th-century construction. Its Proto-Germanic rune names are all reconstructed (no Elder-period name is directly attested).', see: 'pages/runes.html' },
  { term: 'Futhark', cat: 'Runes', def: 'A runic alphabet, named (like "alphabet" from alpha-beta) after its first six staves f-u-þ-a-r-k. The Elder Futhark has 24 runes; the later Younger Futhark reduced them to 16.', see: 'pages/runes.html' },
  { term: 'Ætt (ættir)', cat: 'Runes', def: 'One of the three groups of eight into which the 24 Elder staves are divided (plural ættir). The division itself is attested (Vadstena & Grumpan bracteates, c. 500 CE); the group names "Freyr’s / Hagall’s / Týr’s ætt" are a later Icelandic tradition, not attested for the Elder period.', see: 'pages/runes.html' },
  { term: 'Rune Poems', cat: 'Runes', def: 'The three medieval poems whose stanzas gloss the rune names — the Old English Rune Poem (8th–9th c.; sole MS burned 1731, surviving via Hickes 1705), the Old Norwegian (13th c.) and the Old Icelandic (c. 1500). The Norse poems cover only the 16 Younger Futhark runes, so exactly 8 Elder staves have no Norse stanza. They are the closest thing to "attested" rune meanings — riddle verse about later rune-rows, not a divination table.', see: 'pages/runes.html' },
  { term: 'Tacitus Lot-Cast', cat: 'Runes', def: 'The lot-divination Tacitus describes in Germania 10 (98 CE): marked strips of wood ("notis quibusdam discretos") scattered on a white cloth and taken up three times. The only DETAILED ancient description of the procedure (Caesar, De Bello Gallico 1.50, also briefly attests Germanic lot-casting). Whether the marks were runes is disputed and probably unanswerable — shown only as the prototype of scattered-lot divination.', see: 'pages/runes.html' },
  { term: 'Blank Rune (modern)', cat: 'Runes', def: 'A 25th blank tile ("Odin’s rune", "the Unknowable") added by Ralph Blum in The Book of Runes (1982/83). It has NO ancient attestation — first documented in Blum, possibly present in a 1970s commercial set — and is rejected by traditionalist practitioners (though some pragmatist readers keep it). Excluded from this site’s 24-stave data.', see: 'pages/runes.html' },
  { term: 'Merkstave (Reversed Rune)', cat: 'Runes', def: 'A rune read upside-down or reversed for a shadow/blocked meaning — a modern practice with no medieval attestation, and impossible for the 9 Elder staves that are rotation-symmetric. Not used on this site.', see: 'pages/runes.html' },

  // — Rasaśāstra —
  { term: 'Rasaśāstra', cat: 'Rasaśāstra', def: 'The medieval Indian alchemy of mercury (pārada): a chain of tantric texts that claimed refined mercury could transmute base metal to gold (lohavedha) and perfect the body toward immortality (dehavedha). Chemically it was mercury–sulphur–mica processing (P.C. Ray, 1902/09); the claims have no demonstrated validity, and its substances are toxic — history of chemistry only.', see: 'pages/rasa.html' },
  { term: 'Saṃskāra (mercury)', cat: 'Rasaśāstra', def: 'One of the eighteen ritual "processings" of mercury (Rasahṛdayatantra; Rasaratnasamuccaya ch. 11). The first eight (aṣṭasaṃskāra) were held sufficient to make mercury fit for medicine; the rest pushed toward vedha. Historical record only — no method or dosage is given.', see: 'pages/rasa.html' },
  { term: 'Navagraha yantra', cat: 'Rasaśāstra', def: 'The nine planetary 3×3 magic squares (Sūrya to Ketu), each L1 + (k−1) over the double-flipped Lo Shu, with magic constants 15…39 (step 3) and grand total 729. The modern printed ("bazaar") tradition — flagged as such, not a dated classical text; contrast Agrippa\'s kameas, where Saturn (not the Sun) takes the 3×3.', see: 'pages/rasa.html' },
  { term: 'Chautisa yantra', cat: 'Rasaśāstra', def: 'The 4×4 magic square inscribed at the Pārśvanātha Jain temple, Khajuraho (10th–12th c.) — a most-perfect pandiagonal square: every row, column, diagonal, broken diagonal, wrapping 2×2 block and corner quad sums to 34. Named for that constant (chautīs = thirty-four).', see: 'pages/rasa.html' },
  { term: 'Kaṭapayādi', cat: 'Rasaśāstra', def: 'A Kerala letter-numeration hiding numbers in words: consonants map to digits (ka/ṭa/pa/ya = 1 …), only the last consonant of a cluster counts, vowelless consonants drop out, and digits read right-to-left. Earliest use Haridatta, 683 CE; e.g. the melakartā rāga Dhīraśaṅkarābharaṇam encodes 29.', see: 'pages/rasa.html' },
  { term: 'Sarvatobhadra Chakra', cat: 'Rasaśāstra', def: 'The "auspicious-in-every-direction" 9×9 (81-cell) transit grid of jyotiṣa: 28 nakṣatras on the border, 16 vowels on the diagonals, 20 consonants (ring 2, flagged), 12 rāśis, and tithi-group/weekday cells. A planet in a border nakṣatra "pierces" (vedha) along a front line and two diagonals; the rules and the primary source (Narapatijayacaryā 1176 CE vs the Brahmayāmala) are contested.', see: 'pages/rasa.html' },

  // — Chart calculation (casting by hand) —
  { term: 'Sidereal time (LST)', cat: 'Chart calculation', def: 'The Local Sidereal Time — the sky’s own clock at a place, equal to the right ascension currently on the meridian. Casting by hand: LST = sidereal time at prior midnight + the UT interval + the acceleration on that interval + longitude ÷ 15 (East adds, West subtracts). It fixes the Midheaven and Ascendant. Equivalently RAMC ÷ 15.', see: 'pages/handcalc.html' },
  { term: 'Proportional logarithms', cat: 'Chart calculation', def: 'The classical labour-saver for interpolation: plog(x) = log₁₀(1440 ÷ x-in-minutes), so plog(daily motion) + plog(interval) = plog(the correction to add). Two table look-ups and one addition replace a multiplication. A computational shortcut, not an accuracy gain (per DeVore).', see: 'pages/handcalc.html' },
  { term: 'Ephemeris', cat: 'Chart calculation', def: 'A table of planetary positions at a regular instant each day — for chart calculation, the MIDNIGHT (0h UT) edition, since the hand formulae use midnight positions. A planet’s place at the birth moment is interpolated between two successive midnight lines.', see: 'pages/handcalc.html' },
  { term: 'Table of Houses', cat: 'Chart calculation', def: 'A printed book giving the Midheaven, Ascendant and intermediate cusps by sidereal-time rows and latitude columns, for a house system (e.g. the Michelsen Book of Tables tabulates Placidus and Koch, latitudes 0–60°N). The cusps for an exact chart are read by double interpolation — between the two bracketing sidereal-time rows and the two bracketing latitudes.', see: 'pages/handcalc.html' },
  { term: 'ΔT (Delta T)', cat: 'Chart calculation', def: 'The slowly varying difference between Universal Time (clock time, tied to Earth’s rotation) and the uniform Ephemeris/Terrestrial Time in which planetary tables are computed — tabulated in the Book of Tables. It matters most for the fast Moon and for historical dates.', see: 'pages/handcalc.html' },
  { term: 'Swiss Ephemeris', cat: 'Chart calculation', def: 'The high-precision astronomical library derived from NASA-JPL’s DE ephemerides (sub-arc-second over roughly ±5000 years), maintained by Astrodienst and used by most professional astrology software (astro.com, Solar Fire, Astro Gold, Morinus, Delphic Oracle, Maitreya, Jagannatha Hora). This site computes with the MIT-licensed astronomy-engine at about one arc-minute instead — ample for degree-based traditional work, and stated plainly on the comparison page.', see: 'pages/compare.html#matrix' },

  // — Timing (transits, returns) —
  { term: 'Transit', cat: 'Timing', def: 'Where a planet is on a given date, measured against a birth chart. A transit "hits" a natal point when it perfects a Ptolemaic aspect to it (conjunction, sextile, square, trine, opposition). Dorotheus (Carmen IV.1) and Ptolemy (Tetrabiblos IV.10) judge the year partly by the transits to the profected places.', see: 'pages/transits.html' },
  { term: 'Applying / Separating (transit)', cat: 'Timing', def: 'A transiting aspect is applying while the transiting planet moves toward exactitude (the event is forming), separating once it moves away (past). An exact hit is the instant between the two.', see: 'pages/transits.html' },
  { term: 'Retrograde pass', cat: 'Timing', def: 'When a slower planet crosses a natal point, then retrogrades back over it, then turns direct and crosses a third time — the classic 1-or-3 passes of one transit or a Saturn return (the middle pass retrograde).', see: 'pages/transits.html' },
  { term: 'House overlay', cat: 'Timing', def: 'In synastry, dropping one person’s planets into the other’s houses — the areas of the host’s life the guest’s planets are said to animate. Computed both ways.', see: 'pages/synastry.html' },
  { term: 'Lunar return', cat: 'Timing', def: 'The instant the transiting Moon regains its natal longitude — about 13 a year; the chart cast for it is a "monthly return." The medieval "monthly revolution" was computed several ways (Sun-based or Moon-based) and is flagged, not resolved.', see: 'pages/transits.html' },

  // — Abhicāra & the ṣaṭkarman —
  { term: 'Abhicāra', cat: 'Abhicāra', def: 'The tantric tradition’s own word for hostile ritual (“sorcery”). “Black magic” is a colonial/modern gloss, not the texts’ category. Described here as religious history, never prescribed.', see: 'pages/abhichara/index.html' },
  { term: 'Ṣaṭkarman', cat: 'Abhicāra', def: 'The “six acts” of tantric ritual magic — śānti (pacification), vaśīkaraṇa (subjugation), stambhana (immobilization), vidveṣaṇa (discord), uccāṭana (eradication), māraṇa (slaying). Texts call the group “six” even when they list seven or eight.', see: 'pages/abhichara/six-acts.html' },
  { term: 'Vaśīkaraṇa', cat: 'Abhicāra', def: 'Subjugation — bringing a person, animal or deity under one’s will; the one act the sources perform with the left (vāma) hand.', see: 'pages/abhichara/six-acts.html' },
  { term: 'Stambhana', cat: 'Abhicāra', def: '“Obstructing an activity” — to paralyse or arrest (armies, speech, a rival’s mind). Grouped with māraṇa as suited to the dark fortnight.', see: 'pages/abhichara/six-acts.html' },
  { term: 'Uccāṭana', cat: 'Abhicāra', def: '“Deprivation from a place” — driving a target out of home, family or office; season varṣā (the rains).', see: 'pages/abhichara/six-acts.html' },
  { term: 'Māraṇa', cat: 'Abhicāra', def: 'The māraṇa-class act, “the taking of life” (Bühnemann/Goudriaan render it “liquidation,” Ullrey “murder” — disputed). Recorded ONLY as a textual claim with its symbolic correspondences, as religious history — never a procedure.', see: 'pages/abhichara/six-acts.html' },
  { term: 'Kṛtyā', cat: 'Abhicāra', def: 'The sorcery itself made into a thing (often a fashioned figure), “prepared” and sent against a victim. The Atharvan kṛtyāpratiharaṇa / pratyabhicāra charms name it, reverse it, and return it to its sender.', see: 'pages/abhichara/atharvan.html' },

  // — Yoga Sūtras —
  { term: 'Yoga Sūtras', cat: 'Yoga Sūtras', def: 'The Pātañjala Yoga-sūtra: a treatise of ~196 aphorisms in four books (pādas) attributed to Patañjali (c. 325–425 CE, per Maas), defining yoga as citta-vṛtti-nirodha — the stilling of the fluctuations of mind-stuff — and its Sāṃkhya-derived path to kaivalya (isolation).', see: 'pages/yoga/index.html' },
  { term: 'Aṣṭāṅga (eight limbs)', cat: 'Yoga Sūtras', def: 'The "eight limbs" (aids) of yoga listed at Yoga Sūtra II.29: yama, niyama, āsana, prāṇāyāma, pratyāhāra, dhāraṇā, dhyāna, samādhi. Aids, not a strict ladder; the last three combined on one object are saṃyama.', see: 'pages/yoga/theory.html#astanga' },
  { term: 'Yama & Niyama', cat: 'Yoga Sūtras', def: 'The first two limbs — the five abstentions (ahiṃsā, satya, asteya, brahmacarya, aparigraha; II.30) and the five observances (śauca, santoṣa, tapas, svādhyāya, īśvara-praṇidhāna; II.32). Kept universally, the yamas are the mahāvrata, the "great vow".', see: 'pages/yoga/theory.html#astanga' },
  { term: 'Āsana (in the YS)', cat: 'Yoga Sūtras', def: 'In the Yoga Sūtras āsana is defined only as sthira-sukham āsanam, "a stable and easy seat" (II.46–48), and NO posture is named. The familiar named postures (padmāsana etc.) belong to the Vyāsa-bhāṣya and later commentary/haṭha layers.', see: 'pages/yoga/theory.html#asana' },
  { term: 'Samādhi', cat: 'Yoga Sūtras', def: 'Concentration — the eighth limb (III.3): contemplation in which the object alone shines forth, as if the mind were void of itself. Seeded (sabīja) samādhi still rests on an object; seedless (nirbīja) does not.', see: 'pages/yoga/index.html' },
  { term: 'Kaivalya', cat: 'Yoga Sūtras', def: '"Isolation", aloneness — the goal of the Yoga Sūtras (IV.34): the separation of the seer (puruṣa) from the seen (prakṛti and its guṇas), the guṇas resolving back to their source, or the power of consciousness (citi-śakti) grounded in its own form.', see: 'pages/yoga/index.html' },
  { term: 'Vibhūti', cat: 'Yoga Sūtras', def: 'The "powers" (siddhis) catalogued in Book III as arising from saṃyama — from knowledge of past and future to invisibility and omniscience. The text itself calls them obstacles to samādhi (III.37); described here as the text\'s own claims, never prescribed.', see: 'pages/yoga/theory.html#vibhuti' },
  // — The Great Confluence (R27) —
  { term: 'Transmission (textual)', cat: 'Confluence', def: 'The documented passage of a text or teaching from one language, place or tradition to another — by translation, commentary, adaptation, answer (refutation) or fusion (synthesis). The Great Confluence atlas draws each transmission as a directed arc carrying its own citation: it records that a book was demonstrably read or rendered, never that its doctrine is valid.', see: 'pages/confluence.html' },
  { term: 'Prisca theologia', cat: 'Confluence', def: 'The Renaissance idea of an "ancient theology" — a single primordial wisdom held to descend from Hermes Trismegistus, Zoroaster, Orpheus and Moses to Plato, revived by Ficino and Pico to license their Hermetic–Kabbalistic synthesis. Casaubon’s 1614 redating of the Hermetica broke its chronology; the atlas records it as a documented (and hugely influential) belief, not a fact.', see: 'pages/confluence.html' },
  { term: 'Neidan (internal alchemy)', cat: 'Confluence', def: 'Chinese "inner alchemy": Daoist meditative and physiological cultivation that reworked the vocabulary of waidan (laboratory "outer alchemy") into an internal refinement of qi, jing and shen toward an "immortal embryo." A historical contemplative practice, described here as history, never prescribed.', see: 'pages/confluence.html' },
  { term: 'Dhikr', cat: 'Confluence', def: 'The Sufi "remembrance" of God — the disciplined, often rhythmic repetition of divine names or formulae, silent or vocal, that anchors much Islamic mystical practice. Recorded in the atlas as a described historical devotion of the Sufi lane.', see: 'pages/confluence.html' },
  { term: 'Hesychasm', cat: 'Confluence', def: 'The Eastern-Christian contemplative tradition of inner stillness (hēsychia), centred on the ceaseless "Jesus Prayer" and codified on Mount Athos and in the Philokalia. A historical Christian practice of the contemplation lane, described never prescribed.', see: 'pages/confluence.html' },
  { term: 'Lectio divina', cat: 'Confluence', def: 'The monastic "divine reading" — the slow, prayerful movement through a scriptural text in stages (traditionally reading, meditation, prayer and contemplation, formalised by Guigo II). A documented Western Christian contemplative method in the atlas.', see: 'pages/confluence.html' },
  { term: 'Vipassanā', cat: 'Confluence', def: '"Insight" meditation of the Buddhist traditions — the disciplined observation of experience as impermanent, unsatisfactory and not-self, distinguished from samatha (calm-abiding). Described in the atlas as historical Buddhist practice, never prescribed.', see: 'pages/confluence.html' },
  { term: 'Era-warped scale', cat: 'Confluence', def: 'The Great Confluence timeline’s honest answer to plotting ~3,500 years when most entries fall after 1500 CE: a piecewise-linear vertical axis, truthful within each era band but stepping up its pixels-per-century at explicit boundaries (30 px/century in deep antiquity → 380 near the present). The warp is disclosed on the map itself — every band states its own scale — never hidden.', see: 'pages/how-it-works.html#hiw-confluence' },

  // — Buddhist canon (R30 wing) —
  { term: 'Sutta', cat: 'Buddhist canon', def: 'A discourse of the Buddha (Skt sūtra; lit. "thread"). The prose/verse units of the Pāli Canon\'s Sutta Piṭaka, cited by collection + number (e.g. Snp 1.8, MN 118). Historical texts, described never prescribed.', see: 'pages/buddhist/index.html' },
  { term: 'Gāthā', cat: 'Buddhist canon', def: 'A verse or stanza — the metrical form of texts like the Metta Sutta and the Dhammapada, as opposed to prose (gadya).', see: 'pages/buddhist/metta.html' },
  { term: 'Mettā', cat: 'Buddhist canon', def: '"Loving-kindness / benevolence / active goodwill" (the abstract of mitta, "friend"). The first of the four brahmavihāras ("divine abidings") and the subject of the Metta Sutta (Snp 1.8).', see: 'pages/buddhist/metta.html' },
  { term: 'Sati', cat: 'Buddhist canon', def: '"Mindfulness / awareness / keeping-in-mind" — recollected attention to a chosen object. The faculty cultivated in the satipaṭṭhāna and ānāpānassati practices.', see: 'pages/buddhist/mn118.html' },
  { term: 'Ānāpāna', cat: 'Buddhist canon', def: '"In-breath and out-breath" (āna + apāna). Ānāpānassati = mindfulness of breathing, the sixteen-aspect meditation set out in MN 118.', see: 'pages/buddhist/mn118.html' },
  { term: 'Peyyāla', cat: 'Buddhist canon', def: 'The canonical abbreviation device: a repeated passage is elided with "…pe…" rather than written out. The wing models it with reusable refrains + refrain-use records so a refrain is glossed once and reused honestly.', see: 'pages/buddhist/mn118.html' },
  { term: 'Prajñāpāramitā', cat: 'Buddhist canon', def: '"The perfection of wisdom" (Pāli paññā-pāramī). A Mahāyāna literature-class whose "heart" is condensed in the Heart Sūtra (Prajñāpāramitā-hṛdaya).', see: 'pages/buddhist/heart.html' },
  { term: 'Śūnyatā', cat: 'Buddhist canon', def: '"Emptiness / voidness" — the absence of intrinsic own-being (svabhāva) in phenomena. The central claim of the Heart Sūtra ("form is emptiness, emptiness is form"); reported as the text\'s teaching, not endorsed.', see: 'pages/buddhist/heart.html' },
  { term: 'Dhāraṇā', cat: 'Buddhist canon', def: 'A mnemonic "holding" formula (dhāraṇī, related to Skt √dhṛ "to hold"); the Heart Sūtra\'s closing gate gate… is treated as a dhāraṇī. Glossed here strictly as language, not as an efficacious spell.', see: 'pages/buddhist/heart.html' },
  { term: 'Bhāvanā', cat: 'Buddhist canon', def: '"Cultivation / development / bringing-into-being" (caus. of √bhū) — the standard term for meditative training (e.g. mettā-bhāvanā, "the cultivation of loving-kindness").', see: 'pages/buddhist/index.html' },
  { term: 'Dhammapada', cat: 'Buddhist canon', def: '"The path (pada) of dhamma" — a much-loved anthology of 423 verses in 26 vaggas (chapters), part of the Khuddaka Nikāya. The wing renders vaggas 1–5 (verses 1–75) word-by-word; famous cruxes (manopubbaṅgamā at 1:1, dīpa as "island" vs "lamp" at 20:4) ride in the notes, unresolved.', see: 'pages/buddhist/dhammapada.html' },
  { term: 'Vagga', cat: 'Buddhist canon', def: '"Chapter / section" (literally a "group") — the organizing unit of many Pāli collections. The Dhammapada\'s 423 verses are grouped into 26 named vaggas (Yamaka-, Appamāda-, Citta-vagga …); the reading-room rail groups the verses by their vagga.', see: 'pages/buddhist/dhammapada.html' },

  // — The Practices wing (R31): haṭha-yoga seals & locks —
  { term: 'Mudrā', cat: 'Practices', def: '"Seal / gesture" — in haṭha yoga a sealing technique (as distinct from an āsana posture) said to lock or redirect the breath and the subtle "nectar"; the Gheraṇḍa Saṁhitā teaches 25 mudrās, the Haṭhayogapradīpikā 10. Described as historical doctrine of no demonstrated validity, never prescribed.', see: 'pages/practices/mudras.html' },
  { term: 'Bandha', cat: 'Practices', def: '"Bond / lock" — a muscular contraction (mūla- at the perineum, uḍḍiyāna- at the abdomen, jālandhara- at the throat) counted among the mudrās; the texts claim it seals the breath and the subtle energies. Historical technique, reported never prescribed.', see: 'pages/practices/mudras.html' },
  { term: 'Khecarī', cat: 'Practices', def: '"Moving in space (khe)" — the mudrā in which the tongue is turned back above the soft palate; both the Gheraṇḍa Saṁhitā (3.25) and the Haṭhayogapradīpikā describe a preparatory cutting of the frenum. The site describes this in words and flags it, but never depicts it, and it is not an instruction.', see: 'pages/practices/mudras.html' },
  { term: 'Kumbhaka', cat: 'Practices', def: '"Pot-like" retention of the breath — the held phase of prāṇāyāma that the mudrā chapters presuppose. Named here only as the texts\' own vocabulary; no physiological benefit is asserted by the site.', see: 'pages/practices/mudras.html' },
  { term: 'Haṭha Yoga', cat: 'Practices', def: 'The medieval "forceful" yoga of postures, breath-retention, locks and seals, systematized in texts such as the Haṭhayogapradīpikā (15th c.) and the Gheraṇḍa Saṁhitā (17th c.). The Practices wing catalogues its mudrās as history — a symbolic-esoteric discipline of no demonstrated supernatural validity.', see: 'pages/practices/index.html' },
  { term: 'Granthi', cat: 'Practices', def: '"Knot" — one of three subtle blockages (brahma-, viṣṇu-, rudra-granthi) that the haṭha texts say the roused Kuṇḍalinī must pierce. Reported as the texts\' esoteric physiology, not as anatomy.', see: 'pages/practices/mudras.html' },
  { term: 'Uḍḍiyāna', cat: 'Practices', def: '"Flying up" — the abdominal lock (uḍḍiyāna-bandha) in which the belly is drawn up and back after exhalation; the texts claim it makes the prāṇa "fly up" the central channel. Historical doctrine, described never prescribed.', see: 'pages/practices/mudras.html' },
  { term: 'Mūla-bandha', cat: 'Practices', def: '"Root lock" — contraction of the perineum said to seal the downward apāna and turn it upward. One of the three principal bandhas; reported as the texts\' own technique, not as advice.', see: 'pages/practices/mudras.html' },
  { term: 'Kaṇḍa', cat: 'Practices', def: '"Bulb / root" — the egg-shaped source, about nine finger-widths above the perineum, from which the haṭha texts say the 72,000 nāḍīs (subtle channels) spring. Part of the wing\'s reported esoteric physiology.', see: 'pages/practices/mudras.html' },
  { term: 'Viparītakaraṇī', cat: 'Practices', def: '"The inverted process" — an inversion mudrā (head down, feet up) said to reverse the flow of the "nectar" that otherwise drips from the moon at the palate into the sun at the navel. Described as historical doctrine of no demonstrated validity.', see: 'pages/practices/mudras.html' },

  // — Jyotiṣa: yogas & graha-bala (R28) —
  { term: 'Yoga (planetary combination)', cat: 'Jyotiṣa', def: 'In Jyotiṣa, a named combination of grahas, signs or house-lords to which the classical texts attach a described effect (e.g. Gaja-Kesarī, a Rājayoga, a Dhana yoga). Distinct from the Western/Haṭha senses of "yoga" and from the pañcāṅga yoga. Described as historical doctrine — a symbolic system with no demonstrated validity, never a prediction.', see: 'pages/vedic/index.html' },
  { term: 'Pañca-Mahāpuruṣa Yoga', cat: 'Jyotiṣa', def: 'The five "great person" yogas: one of Mars, Mercury, Jupiter, Venus or Saturn in its own, mūlatrikoṇa or exaltation sign while occupying a kendra (angle) — Ruchaka, Bhadra, Haṁsa, Mālavya, Śaśa respectively. BPHS ch. 75; Phaladīpikā 6.1–4.', see: 'pages/vedic/index.html' },
  { term: 'Rājayoga', cat: 'Jyotiṣa', def: 'A "sovereignty" combination — most centrally a sambandha (relation) between a kendra (angle) lord and a trikoṇa (trine) lord, to which the tradition attaches rank and rising fortune. BPHS chs. 39–40; Laghu Parāśarī. The admissible relation set is itself contested. Doctrine only, no demonstrated validity.', see: 'pages/vedic/index.html' },
  { term: 'Dhana yoga', cat: 'Jyotiṣa', def: 'A "wealth" combination. BPHS ch. 41 gives concrete own-sign and 5th/11th patterns; the abstract 2nd/11th-lord grid is a modern (Raman-era) systematization, flagged as such. Historical doctrine, described never prescribed.', see: 'pages/vedic/index.html' },
  { term: 'Vipreet Rājayoga', cat: 'Jyotiṣa', def: 'The "inverse" rāja doctrine — Harṣa, Sarala and Vimala — in which a lord of a duḥsthāna (the 6th, 8th or 12th) placed in a duḥsthāna is read as "loss of loss." Loci: Phaladīpikā 6.57/6.63/6.65/6.69 and Uttara Kālāmṛta 4.22 (NOT BPHS ch. 36). The "no association with outside lords" rider and the mutual-relation hardening are contested.', see: 'pages/vedic/index.html' },
  { term: 'Nīca-bhaṅga Rājayoga', cat: 'Jyotiṣa', def: 'The doctrine of "cancelled debilitation": a fallen graha whose fall is claimed undone (raising the native higher than an unafflicted one would). The three texts disagree on the mechanism — BPHS (39.19–28), Phaladīpikā (7.26–30, dispositor in a kendra) and Jātaka Pārijāta each give a different condition set; the detector shows all three and resolves none.', see: 'pages/vedic/index.html' },
  { term: 'Kemadruma Yoga', cat: 'Jyotiṣa', def: 'The lunar-isolation doctrine — no tārā graha with the Moon nor in her 2nd or 12th (the inverse of the Sunaphā family). The texts describe it in deliberately harsh terms; the later literature is dominated by disputed cancellation (bhaṅga) lists. A medieval doctrine, not anyone’s prospects.', see: 'pages/vedic/index.html' },
  { term: 'Gaja-Kesarī Yoga', cat: 'Jyotiṣa', def: 'The "elephant-lion" yoga — Jupiter in a kendra from the Moon. Contested: the bare rule (Phaladīpikā 6.14) versus the conditioned form (BPHS 36.3–4: kendra from Lagna or Moon + benefic association, free of debilitation/combustion/inimical sign). The bare form recurs in roughly a quarter of charts — the dispute the playlist’s own session 124 engages.', see: 'pages/vedic/index.html' },
  { term: 'Budha-Āditya Yoga', cat: 'Jyotiṣa', def: 'The Sun–Mercury conjunction, credited with intelligence and eloquence. The NAME is late (modern manuals); the effects rest on the classical two-graha yuti literature (Sārāvalī 15.4). Mercury is astronomically never far from the Sun, so the bare conjunction is common.', see: 'pages/vedic/index.html' },
  { term: 'Kendrādhipati Doṣa', cat: 'Jyotiṣa', def: 'The functional-benefic doctrine that a natural benefic owning a kendra (4th/7th/10th) loses its disposition to do good (Jupiter and Venus most of all). Laghu Parāśarī; contested by Uttara Kālāmṛta’s narrower reading. An affliction rule, not a fruit; it predicts nothing about health or lifespan.', see: 'pages/vedic/index.html' },
  { term: 'Parivartana (sign exchange)', cat: 'Jyotiṣa', def: 'A mutual exchange of signs between two grahas (each occupies a sign the other rules). Phaladīpikā 6.32 classes them Mahā (favourable-house lords), Khala (with the 3rd lord) and Dainya (a duḥsthāna lord involved) — the last collides head-on with the Vipreet doctrine, shown both ways.', see: 'pages/vedic/index.html' },
  { term: 'Kāla-Sarpa Yoga', cat: 'Jyotiṣa', def: 'A MODERN doctrine (no classical locus — absent from BPHS, Phaladīpikā, Sārāvalī and Bṛhat Jātaka) in which all seven classical grahas are hemmed on one side of the Rāhu–Ketu axis. Definition is unstable (sign- vs degree-based hemming); it is the yoga most often used to sell remedies. Documented, never endorsed.', see: 'pages/vedic/index.html' },
  { term: 'Graha Dṛṣṭi', cat: 'Jyotiṣa', def: 'Planetary "aspect" in Jyotiṣa. Every graha aspects the 7th sign from itself; Mars also the 4th & 8th, Jupiter the 5th & 9th, Saturn the 3rd & 10th (whole-sign, the taught form). BPHS Ch. 26 also gives a degree-graded (sphuṭa) virūpa scheme — a genuine contested presentation choice, shown both ways.', see: 'pages/vedic/index.html' },
  { term: 'Asta (combustion)', cat: 'Jyotiṣa', def: 'A graha "combust" — too close to the Sun by longitude and so held weakened. The arcs are contested across sources: Moon 12°, Mars 17°, Mercury 14° (12° retro), Jupiter 11°, Venus 10° (8°–9° retro), Saturn 15°. The Sun is the source and never combust; the nodes are excluded.', see: 'pages/vedic/index.html' },
  { term: 'Pañcadhā Maitrī', cat: 'Jyotiṣa', def: 'The "five-fold" compound friendship (BPHS 3.55–60): the naisargika (permanent, natural) friendship of two grahas compounded with their tātkālika (temporary, by the 2/3/4/10/11/12 count) relation into great-friend / friend / neutral / enemy / great-enemy. Feeds the ṣaḍbala saptavargaja strength.', see: 'pages/vedic/index.html' },
  { term: 'Bhāva-phala (planet-in-house)', cat: 'Jyotiṣa', def: 'The classical "effects of a graha in a bhāva" delineation literature. The corpus here keeps two witnesses side by side and never merged — Phaladīpikā ch. 8 (all nine grahas) and Sārāvalī ch. 30 (Sun–Saturn only; the nodes are single-witness) — displaying inter-text contradiction as a feature. Historical doctrine, described never prescribed.', see: 'pages/vedic/index.html' },

  // — Jyotiṣa: house classifications & the Parāśarī course (R29) —
  { term: 'Trikoṇa', cat: 'Jyotiṣa', def: 'The trine houses — the 1st, 5th and 9th. With the kendras (angles) they are the auspicious houses of the chart, and a graha owning both a trikoṇa and a kendra is a yogakāraka. BPHS ch. 34.', see: 'pages/vedic/course.html' },
  { term: 'Trika (Duḥsthāna)', cat: 'Jyotiṣa', def: 'The three "difficult" houses — the 6th, 8th and 12th (of illness/debt/enmity, sudden reversal, and loss/expenditure respectively). Their lords are read as afflicting, and the inverse Vipreet doctrine turns on them. BPHS ch. 34.', see: 'pages/vedic/course.html' },
  { term: 'Upachaya', cat: 'Jyotiṣa', def: 'The "growth" houses — the 3rd, 6th, 10th and 11th — held to improve with time, so that even malefics placed there are read as gaining. BPHS ch. 34.', see: 'pages/vedic/course.html' },
  { term: 'Triṣaḍāya', cat: 'Jyotiṣa', def: 'The houses 3, 6 and 11 taken together — the triad the Laghu Parāśarī treats as the "evil" upachaya set whose lords behave malefically regardless of nature. Laghu Parāśarī.', see: 'pages/vedic/course.html' },
  { term: 'Yogakāraka', cat: 'Jyotiṣa', def: 'A graha that rules BOTH a kendra (angle) and a trikoṇa (trine) for a given lagna — the single most auspicious functional role, taken to give a rājayoga by itself (classically Mars for Cancer/Leo lagnas, Venus for Capricorn/Aquarius, Saturn for Taurus/Libra). BPHS 34.13–20.', see: 'pages/vedic/course.html' },
  { term: 'Māraka', cat: 'Jyotiṣa', def: '"Killer" — in the tradition\'s length-of-life doctrine, the lords and occupants of the 2nd and 7th houses, classed as the agents that may end a period of life. Shown here strictly as a historical CLASSIFICATION, never a date, span, danger-period or prediction (the hyleg/alcocoden precedent). BPHS ch. 44.', see: 'pages/vedic/course.html' },
  { term: 'Bhāveśa', cat: 'Jyotiṣa', def: 'A house-lord — the graha ruling the sign on a given bhāva ("the lord of X in Y"). The functional relationships between bhāveśas (kendra/trikoṇa lords vs duḥsthāna lords) underlie the rāja, dhana and inverse yogas. BPHS ch. 24.', see: 'pages/vedic/course.html' },
  { term: 'Naisargika Maitrī', cat: 'Jyotiṣa', def: 'The permanent (natural) friendship, enmity or neutrality between two grahas, fixed by rulership regardless of the chart — the base compounded with the temporary relation into the five-fold Pañcadhā Maitrī. BPHS 3.55–57.', see: 'pages/vedic/course.html' },

  // — Thelemic time tools (R29) —
  { term: 'Era Legis (Anno notation)', cat: 'Magic', def: "The Thelemic calendar's way of writing a year: 'Anno {docosade}{year}', counted from the vernal equinox of 1904 (the New Aeon epoch) in 22-year cycles — the docosade as an upper-case Roman numeral and the year within it (0–21) as a lower-case one (e.g. Vxii = docosade 5, year 12). Aleister Crowley's calendrical practice; a notation with no astrological validity.", see: 'pages/thelemic-times.html#hiw-thelemic' },
  { term: 'Docosade', cat: 'Magic', def: 'In the Thelemic calendar, a 22-year cycle. Years since the 1904 epoch are grouped into docosades; a date\'s docosade number is the upper-case Roman numeral of the "Anno" stamp.', see: 'pages/thelemic-times.html#hiw-thelemic' },
  { term: 'The New Aeon epoch', cat: 'Magic', def: 'The zero-point of the Thelemic calendar: the northern vernal equinox of 1904, the year Liber AL vel Legis was received. Year 0 of the New Aeon; all Era Legis dates count from it.', see: 'pages/thelemic-times.html#hiw-thelemic' },
  { term: 'Liber Resh', cat: 'Magic', def: 'Liber Resh vel Helios (Aleister Crowley, 1911) — a short text whose four daily adorations of the Sun are timed to sunrise, noon, sunset and midnight, under the names Ra, Ahathoor, Tum and Khephra. Reproduced here as historical astronomy + rubric, cited to the public-domain 1911 printing; no demonstrated validity.', see: 'pages/thelemic-times.html' },

  // — The Eastern Greats (R32, phase E1) —
  { term: 'Bṛhajjātaka (Bṛhat Jātaka)', cat: 'Jyotiṣa', def: 'Varāhamihira’s c. 550 CE "Great Nativity" — the standard classical Sanskrit manual of natal astrology (horā), 28 adhyāyas. US public domain in BOTH standard English translations (N. Chidambaram Iyer / N. C. Aiyar 1885; V. Subrahmanya Sastri, Mysore, 1929). Its methods are catalogued as a historical symbolic system of no demonstrated predictive validity.', see: 'pages/vedic/index.html' },
  { term: 'Bṛhat Saṁhitā', cat: 'Jyotiṣa', def: 'Varāhamihira’s c. 550 CE "Great Compendium" (~106 chapters) — an encyclopaedia of omens, mundane astrology, muhūrta, architecture (vāstu), gemmology and natural science. Distinct from his natal Bṛhajjātaka. PD English: Iyer, 1884; the 1946 Sastri/Bhat edition is URAA-restored (US PD 2042), cite-only.', see: 'pages/muhurta.html' },
  { term: 'Pañcasiddhāntikā', cat: 'Jyotiṣa', def: 'Varāhamihira’s digest of five earlier astronomical schools (siddhāntas) — the gaṇita (mathematical-astronomy) substrate under the astrology, several of its sources otherwise lost. PD English: Thibaut & Sudhākara Dvivedī, Benares, 1889. Maps to the site’s cast-by-hand / learn-the-math layer, not to a predictive tool.', see: 'pages/handcalc.html' },
  { term: 'Āyurdāya (longevity)', cat: 'Jyotiṣa', def: '"Length-of-life" reckoning — the intricate span-of-life computations (piṇḍāyu, aṁśāyu, naisargikāyu and the haraṇa reductions) of classical jyotiṣa, e.g. Bṛhajjātaka ch. VII, whose result is distributed by the daśā periods. Catalogued as the text’s historical predictive method, never asserted as valid.', see: 'pages/timelords.html' },
  { term: 'Kriya Yoga (Lahiri–Yogananda lineage)', cat: 'Yoga Sūtras', def: 'The prāṇāyāma / life-energy technique of the Babaji→Lahiri Mahasaya→Sri Yukteswar→Yogananda lineage, popularized by Autobiography of a Yogi (ch. 26). DISAMBIGUATION: this is NOT Patañjali’s kriyā-yoga of Yoga Sūtra II.1 (tapas–svādhyāya–īśvarapraṇidhāna) — the shared term is a collision, not an identity. Presented as the lineage’s own teaching claim; no technique is instructed.', see: 'pages/yoga/pada2.html' },
  { term: 'Rāja Yoga (Vivekananda)', cat: 'Yoga Sūtras', def: 'Vivekananda’s 1896 book (US public domain) — lectures plus his "rather free translation" of and commentary on Patañjali’s Yoga Sūtras, recast as an experimental "science of the mind" for Western readers. The site treats it as his RENDERING/reception layer, cross-linked to the Yoga Sūtras wing and labelled as his interpretation, not the sūtra text; its prāṇa/ākāśa framing is flagged as 1890s vitalism.', see: 'pages/yoga/index.html' },
];

export const GLOSSARY_CATEGORIES = [...new Set(GLOSSARY.map(g => g.cat))].sort();
